code_string = """from qiskit import transpile
from scipy.optimize import minimize

def run_and_analyze(circuit, aer_sim, graph):
    circuit = transpile(circuit, aer_sim)

    def objective(params):
        parameter_binds = [{p: [v] for p, v in zip(circuit.parameters, params)}]
        job = aer_sim.run(circuit, parameter_binds=parameter_binds, shots=8192)
        counts = job.result().get_counts()
        reversed_counts = {k[::-1]: v for k, v in counts.items()}
        return -compute_expectation(reversed_counts, graph)

    initial_params = [0.5] * circuit.num_parameters
    result = minimize(objective, initial_params, method='COBYLA')

    parameter_binds = [{p: [v] for p, v in zip(circuit.parameters, result.x)}]
    job = aer_sim.run(circuit, parameter_binds=parameter_binds, shots=8192)
    counts = job.result().get_counts()

    sorted_counts = sorted(counts.items(), key=lambda x: -x[1])
    top_two = [state[::-1] for state, _ in sorted_counts[:2]]

    return top_two
"""
